{
    version     2.0;
    format      ascii;
    class       dictionary;
    object      fvOptions;
}

cellSets
{
    obstacleRegion
    {
        type    cellSet;
        set     obstacleCell;
    }
}

fields
{
    U
    {
        porousExplicitSourceCoeffs
        {
            type            porousExplicitSource;
            porousType      combined;
            porositySource  obstacleRegion;
            value           uniform (0 0 0);
        }
    }

    p_rgh
    {
        porousExplicitSourceCoeffs
        {
            type            porousExplicitSource;
            porousType      combined;
            porositySource  obstacleRegion;
            value           uniform 0;
        }
    }
}
```

Then modify `system/fvSolution` to include `fvOptions` in the PIMPLE loop by adding:
```
